mapper.select:
SELECT COUNT(*) as CNT
FROM tb_cs_upload_dir 
WHERE dir = #{uploadDir}

mapper.update:

		UPDATE tb_cs_upload_dir
      	SET use_yn = 'Y'	
       WHERE dir = #{uploadDirChange}

mapper.select:
select dir
from tb_cs_last_read
where category = #{category}

mapper.insert:
        insert tb_cs_last_read (
			category
